import pytest
from typing import Any

def title_case(s: str) -> str:
    return ' '.join(word.capitalize() for word in s.split())

class TestTitleCase:
    # Happy path tests
    def test_single_word(self):
        assert title_case("hello") == "Hello"

    def test_multiple_words(self):
        assert title_case("hello world") == "Hello World"

    def test_multiple_words_with_extra_spaces(self):
        assert title_case("hello    world") == "Hello World"

    def test_already_title_case(self):
        assert title_case("Hello World") == "Hello World"

    def test_mixed_case(self):
        assert title_case("hELLo WoRLd") == "Hello World"

    def test_single_letter_words(self):
        assert title_case("a b c") == "A B C"

    def test_words_with_numbers(self):
        assert title_case("hello123 world456") == "Hello123 World456"

    def test_words_with_punctuation(self):
        assert title_case("hello, world!") == "Hello, World!"

    # Edge cases
    def test_empty_string(self):
        assert title_case("") == ""

    def test_only_spaces(self):
        assert title_case("   ") == ""

    def test_single_space(self):
        assert title_case(" ") == ""

    def test_single_character(self):
        assert title_case("a") == "A"

    def test_single_character_space(self):
        assert title_case(" a ") == "A"

    def test_newlines_and_tabs(self):
        assert title_case("hello\tworld\npython") == "Hello\tWorld\nPython"

    def test_consecutive_spaces(self):
        assert title_case("hello  world   python") == "Hello World Python"

    # Error cases
    def test_non_string_input(self):
        with pytest.raises(AttributeError):
            title_case(123)  # type: ignore

    def test_none_input(self):
        with pytest.raises(AttributeError):
            title_case(None)  # type: ignore

    def test_list_input(self):
        with pytest.raises(AttributeError):
            title_case(["hello", "world"])  # type: ignore

    def test_dict_input(self):
        with pytest.raises(AttributeError):
            title_case({"hello": "world"})  # type: ignore

